import React from 'react';
import 'flag-icons/css/flag-icons.min.css';

/**
 * FlagIcon component renders SVG flag icons using the flag-icons library
 * @param {string} countryCode - ISO 3166-1 alpha-2 country code (e.g., 'US', 'GB', 'FR')
 * @param {string} size - Size of the flag (default: '1em')
 * @param {string} className - Additional CSS classes
 */
const FlagIcon = ({ countryCode, size = '1em', className = '' }) => {
  if (!countryCode) {return null;}
  
  const code = countryCode.toLowerCase();
  
  return (
    <span 
      className={`fi fi-${code} ${className}`}
      style={{ 
        fontSize: size,
        marginRight: '8px',
        verticalAlign: 'middle'
      }}
    />
  );
};

export default FlagIcon;
